import{_ as e,c as p}from"./app.90a21e26.js";const r={},c=p('<h1 id="_24-\u8BB2-\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10-\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B-api-\u6D4B\u8BD5\u8981\u600E\u4E48\u505A" tabindex="-1"><a class="header-anchor" href="#_24-\u8BB2-\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10-\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B-api-\u6D4B\u8BD5\u8981\u600E\u4E48\u505A" aria-hidden="true">#</a> 24 \u8BB2\uFF1A\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10\uFF1A\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B API \u6D4B\u8BD5\u8981\u600E\u4E48\u505A\uFF1F</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\uFF0C\u4ECA\u5929\u6211\u5206\u4EAB\u7684\u4E3B\u9898\u662F\u201C\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10\uFF1A\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B API \u6D4B\u8BD5\u8981\u600E\u4E48\u505A\uFF1F\u201D\u3002</p><p>\u901A\u8FC7\u4E00\u4E2A\u7684 Restful API \u5B9E\u4F8B\uFF0C\u6211\u4ECB\u7ECD\u4E86 cURL \u548C Postman \u5DE5\u5177\u7684\u57FA\u672C\u7528\u6CD5\uFF0C\u8FD9\u6837\u6211\u4EEC\u5BF9 API \u6D4B\u8BD5\u6709\u4E86\u4E00\u4E2A\u611F\u6027\u8BA4\u8BC6\uFF1B\u5728\u6B64\u57FA\u7840\u4E0A\uFF0C\u6211\u4ECB\u7ECD\u4E86 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u53D1\u5C55\u7684\u6765\u9F99\u53BB\u8109\uFF0C\u501F\u6B64\u6211\u4EEC\u5BF9 API \u6D4B\u8BD5\u6846\u67B6\u7684\u7406\u89E3\u53C8\u66F4\u6DF1\u5165\u4E86\u4E00\u5C42\u3002</p><p>\u4ECA\u5929\uFF0C\u6211\u5C06\u66F4\u8FDB\u4E00\u6B65\uFF0C\u5E26\u4F60\u53BB\u4E86\u89E3\u5F53\u4E0B\u6700\u70ED\u95E8\u7684\u6280\u672F\u9886\u57DF\u7684 API \u6D4B\u8BD5\uFF0C\u5373\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B\u7684 API \u6D4B\u8BD5\u3002\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0CAPI \u6D4B\u8BD5\u7684\u6700\u5927\u6311\u6218\u6765\u81EA\u4E8E\u5E9E\u5927\u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\uFF0C\u4EE5\u53CA\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u76F8\u4E92\u8026\u5408\u3002\u6240\u4EE5\uFF0C\u6211\u4ECA\u5929\u5206\u4EAB\u8FD9\u4E2A\u4E3B\u9898\u7684\u76EE\u7684\u5C31\u662F\uFF0C\u5E2E\u4F60\u7406\u89E3\u8FD9\u4E24\u4E2A\u95EE\u9898\u7684\u672C\u8D28\uFF0C\u4EE5\u53CA\u5982\u4F55\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684\u65B9\u6CD5\u6765\u5E94\u5BF9\u8FD9\u4E24\u4E2A\u96BE\u9898\u3002</p><p>\u800C\u4E3A\u4E86\u638C\u63E1\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B\u7684 API \u6D4B\u8BD5\uFF0C\u4F60\u9700\u8981\u5148\u4E86\u89E3\u5FAE\u670D\u52A1\u67B6\u6784\uFF08Microservice Architecture\uFF09\u7684\u7279\u70B9\u3001\u6D4B\u8BD5\u6311\u6218\uFF1B\u800C\u8981\u4E86\u89E3\u5FAE\u670D\u52A1\u67B6\u6784\uFF0C\u4F60\u53C8\u9700\u8981\u5148\u4E86\u89E3\u4E00\u4E9B\u5355\u4F53\u67B6\u6784\uFF08Monolithic Architecture\uFF09\u7684\u77E5\u8BC6\u3002\u6240\u4EE5\uFF0C\u4ECA\u5929\u7684\u8BDD\u9898\u6211\u5C06\u9010\u5C42\u5C55\u5F00\uFF0C\u76EE\u7684\u5C31\u662F\u5E0C\u671B\u4F60\u53EF\u4EE5\u771F\u6B63\u7406\u89E3\uFF0C\u5E76\u5FEB\u901F\u638C\u63E1\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B\u7684 API \u6D4B\u8BD5\u3002</p><p><strong>\u5355\u4F53\u67B6\u6784\uFF08Monolithic Architecture\uFF09</strong></p><p>\u5355\u4F53\u67B6\u6784\u662F\u65E9\u671F\u7684\u67B6\u6784\u6A21\u5F0F\uFF0C\u5E76\u4E14\u5B58\u5728\u4E86\u5F88\u957F\u65F6\u95F4\u3002\u5355\u4F53\u67B6\u6784\u662F\u5C06\u6240\u6709\u7684\u4E1A\u52A1\u573A\u666F\u7684\u8868\u793A\u5C42\u3001\u4E1A\u52A1\u903B\u8F91\u5C42\u548C\u6570\u636E\u8BBF\u95EE\u5C42\u653E\u5728\u540C\u4E00\u4E2A\u5DE5\u7A0B\u4E2D\uFF0C\u6700\u7EC8\u7ECF\u8FC7\u7F16\u8BD1\u3001\u6253\u5305\uFF0C\u5E76\u90E8\u7F72\u5728\u670D\u52A1\u5668\u4E0A\u3002</p><p>\u6BD4\u5982\uFF0C\u7ECF\u5178\u7684 J2EE \u5DE5\u7A0B\uFF0C\u5B83\u5C31\u662F\u5C06\u8868\u793A\u5C42\u7684 JSP\u3001\u4E1A\u52A1\u903B\u8F91\u5C42\u7684 Service\u3001Controller \u548C\u6570\u636E\u8BBF\u95EE\u5C42\u7684 DAO\uFF08Data Access Objects\uFF09\uFF0C\u6253\u5305\u6210 war \u6587\u4EF6\uFF0C\u7136\u540E\u90E8\u7F72\u5728 Tomcat\u3001Jetty \u6216\u8005\u5176\u4ED6 Servlet \u5BB9\u5668\u4E2D\u8FD0\u884C\u3002</p><p>\u663E\u7136\u5355\u4F53\u67B6\u6784\u5177\u6709\u53D1\u5E03\u7B80\u5355\u3001\u65B9\u4FBF\u8C03\u8BD5\u3001\u67B6\u6784\u590D\u6742\u6027\u4F4E\u7B49\u4F18\u70B9\uFF0C\u6240\u4EE5\u957F\u671F\u4EE5\u6765\u4E00\u76F4\u88AB\u5927\u91CF\u4F7F\u7528\uFF0C\u5E76\u5E7F\u6CDB\u5E94\u7528\u4E8E\u4F20\u7EDF\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u3002</p><p>\u4F46\u662F\uFF0C\u968F\u7740\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u666E\u53CA\uFF0C\u5E94\u7528\u6240\u627F\u8F7D\u7684\u6D41\u91CF\u8D8A\u6765\u8D8A\u5E9E\u5927\uFF0C\u5355\u4F53\u67B6\u6784\u7684\u95EE\u9898\u4E5F\u88AB\u9010\u6E10\u66B4\u9732\u5E76\u4E0D\u65AD\u653E\u5927\uFF0C\u4E3B\u8981\u7684\u95EE\u9898\u6709\u4EE5\u4E0B\u51E0\u70B9\uFF1A</p><ul><li><strong>\u7075\u6D3B\u6027\u5DEE</strong>\uFF1A\u65E0\u8BBA\u662F\u591A\u5C0F\u7684\u4FEE\u6539\uFF0C\u54EA\u6015\u53EA\u4FEE\u6539\u4E86\u4E00\u884C\u4EE3\u7801\uFF0C\u4E5F\u8981\u6253\u5305\u53D1\u5E03\u6574\u4E2A\u5E94\u7528\u3002\u66F4\u7CDF\u7684\u662F\uFF0C\u7531\u4E8E\u6240\u6709\u6A21\u5757\u4EE3\u7801\u90FD\u5728\u4E00\u8D77\uFF0C\u6240\u4EE5\u6BCF\u6B21\u7F16\u8BD1\u6253\u5305\u90FD\u8981\u82B1\u8D39\u5F88\u957F\u65F6\u95F4\u3002</li><li><strong>\u53EF\u6269\u5C55\u6027\u5DEE</strong>\uFF1A\u5728\u9AD8\u5E76\u53D1\u573A\u666F\u4E0B\uFF0C\u65E0\u6CD5\u4EE5\u6A21\u5757\u4E3A\u5355\u4F4D\u7075\u6D3B\u6269\u5C55\u5BB9\u91CF\uFF0C\u4E0D\u5229\u4E8E\u5E94\u7528\u7684\u6A2A\u5411\u6269\u5C55\u3002</li><li><strong>\u7A33\u5B9A\u6027\u5DEE</strong>\uFF1A\u5F53\u5355\u4F53\u5E94\u7528\u4E2D\u4EFB\u4F55\u4E00\u4E2A\u6A21\u5757\u6709\u95EE\u9898\u65F6\uFF0C\u90FD\u53EF\u80FD\u4F1A\u9020\u6210\u5E94\u7528\u6574\u4F53\u7684\u4E0D\u53EF\u7528\uFF0C\u7F3A\u4E4F\u5BB9\u9519\u673A\u5236\u3002</li><li><strong>\u53EF\u7EF4\u62A4\u6027\u5DEE</strong>\uFF1A\u968F\u7740\u4E1A\u52A1\u590D\u6742\u6027\u7684\u63D0\u5347\uFF0C\u4EE3\u7801\u7684\u590D\u6742\u6027\u4E5F\u662F\u76F4\u7EBF\u4E0A\u5347\uFF0C\u5F53\u4E1A\u52A1\u89C4\u6A21\u6BD4\u8F83\u5E9E\u5927\u65F6\uFF0C\u6574\u4F53\u9879\u76EE\u7684\u53EF\u7EF4\u62A4\u6027\u4F1A\u5927\u6253\u6298\u6263\u3002</li></ul><p>\u6B63\u662F\u56E0\u4E3A\u9762\u5BF9\u4E92\u8054\u7F51\u5E94\u7528\u65F6\uFF0C\u5355\u4F53\u67B6\u6784\u6709\u8FD9\u4E00\u7CFB\u5217\u65E0\u6CD5\u903E\u8D8A\u7684\u9E3F\u6C9F\uFF0C\u6240\u4EE5\u50AC\u751F\u4E86\u5FAE\u670D\u52A1\u67B6\u6784\u3002</p><p>\u5176\u5B9E\uFF0C\u5FAE\u670D\u52A1\u67B6\u6784\u4E5F\u4E0D\u662F\u4E00\u8E74\u800C\u5C31\u7684\uFF0C\u4E5F\u7ECF\u5386\u4E86\u5F88\u957F\u65F6\u95F4\u7684\u6F14\u5316\u53D1\u5C55\uFF0C\u4E2D\u95F4\u8FD8\u7ECF\u5386\u4E86\u8457\u540D\u7684 SOA \u67B6\u6784\u3002\u4F46\u662F\u8FD9\u4E2A\u7531\u5355\u4F53\u67B6\u6784\u5230 SOA \u67B6\u6784\u518D\u5230\u5FAE\u670D\u52A1\u67B6\u6784\u7684\u6F14\u8FDB\u8FC7\u7A0B\uFF0C\u5E76\u4E0D\u662F\u672C\u6587\u7684\u91CD\u70B9\uFF0C\u6240\u4EE5\u6211\u5C31\u4E0D\u518D\u8BE6\u7EC6\u5C55\u5F00\u4E86\uFF0C\u5982\u679C\u4F60\u611F\u5174\u8DA3\u7684\u8BDD\uFF0C\u53EF\u4EE5\u81EA\u884C\u53BB\u67E5\u9605\u4E00\u4E9B\u76F8\u5173\u8D44\u6599\u3002</p><p><strong>\u5FAE\u670D\u52A1\u67B6\u6784\uFF08Microservice Architecture\uFF09</strong></p><p>\u5FAE\u670D\u52A1\u662F\u4E00\u79CD\u67B6\u6784\u98CE\u683C\u3002\u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u4E00\u4E2A\u5927\u578B\u590D\u6742\u8F6F\u4EF6\u7CFB\u7EDF\u4E0D\u518D\u7531\u4E00\u4E2A\u5355\u4F53\u7EC4\u6210\uFF0C\u800C\u662F\u7531\u4E00\u7CFB\u5217\u76F8\u4E92\u72EC\u7ACB\u7684\u5FAE\u670D\u52A1\u7EC4\u6210\u3002\u5176\u4E2D\uFF0C\u5404\u4E2A\u5FAE\u670D\u52A1\u8FD0\u884C\u5728\u81EA\u5DF1\u7684\u8FDB\u7A0B\u4E2D\uFF0C\u5F00\u53D1\u548C\u90E8\u7F72\u90FD\u6CA1\u6709\u4F9D\u8D56\u3002</p><p>\u4E0D\u540C\u670D\u52A1\u4E4B\u95F4\u901A\u8FC7\u4E00\u4E9B\u8F7B\u91CF\u7EA7\u4EA4\u4E92\u673A\u5236\u8FDB\u884C\u901A\u4FE1\uFF0C\u4F8B\u5982 RPC\u3001HTTP \u7B49\uFF0C\u670D\u52A1\u53EF\u72EC\u7ACB\u6269\u5C55\u4F38\u7F29\uFF0C\u6BCF\u4E2A\u670D\u52A1\u5B9A\u4E49\u4E86\u660E\u786E\u7684\u8FB9\u754C\uFF0C\u53EA\u9700\u8981\u5173\u6CE8\u5E76\u5F88\u597D\u5730\u5B8C\u6210\u4E00\u4EF6\u4EFB\u52A1\u5C31\u53EF\u4EE5\u4E86\uFF0C\u4E0D\u540C\u7684\u670D\u52A1\u53EF\u4EE5\u6839\u636E\u4E1A\u52A1\u9700\u6C42\u5B9E\u73B0\u7684\u4FBF\u5229\u6027\u800C\u91C7\u7528\u4E0D\u540C\u7684\u7F16\u7A0B\u8BED\u8A00\u6765\u5B9E\u73B0\uFF0C\u7531\u72EC\u7ACB\u7684\u56E2\u961F\u6765\u7EF4\u62A4\u3002</p><p>\u56FE 1 \u5C31\u5F88\u5F62\u8C61\u5730\u5C55\u793A\u4E86\u5355\u4F53\u67B6\u6784\u548C\u5FAE\u670D\u52A1\u67B6\u6784\u4E4B\u95F4\u7684\u5DEE\u5F02\u3002</p><p><img src="https://static001.geekbang.org/resource/image/69/9d/6968c125be2de960b48d8df35315159d.png" alt="\u5355\u4F53\u67B6\u6784 VS \u5FAE\u670D\u52A1\u67B6\u6784"></p><p>\u5FAE\u670D\u52A1\u67B6\u6784\u5177\u6709\u4EE5\u4E0B\u7279\u70B9\uFF1A</p><ul><li>\u6BCF\u4E2A\u670D\u52A1\u8FD0\u884C\u5728\u5176\u72EC\u7ACB\u7684\u8FDB\u7A0B\u4E2D\uFF0C\u5F00\u53D1\u91C7\u7528\u7684\u6280\u672F\u6808\u4E5F\u662F\u72EC\u7ACB\u7684\uFF1B</li><li>\u670D\u52A1\u95F4\u91C7\u7528\u8F7B\u91CF\u7EA7\u901A\u4FE1\u673A\u5236\u8FDB\u884C\u6C9F\u901A\uFF0C\u901A\u5E38\u662F\u57FA\u4E8E HTTP \u534F\u8BAE\u7684 RESTful API\uFF1B</li><li>\u6BCF\u4E2A\u670D\u52A1\u90FD\u56F4\u7ED5\u7740\u5177\u4F53\u7684\u4E1A\u52A1\u8FDB\u884C\u6784\u5EFA\uFF0C\u5E76\u4E14\u80FD\u591F\u88AB\u72EC\u7ACB\u5F00\u53D1\u3001\u72EC\u7ACB\u90E8\u7F72\u3001\u72EC\u7ACB\u53D1\u5E03\uFF1B</li><li>\u5BF9\u8FD0\u7EF4\u63D0\u51FA\u4E86\u975E\u5E38\u9AD8\u7684\u8981\u6C42\uFF0C\u4FC3\u8FDB\u4E86 CI/CD \u7684\u53D1\u5C55\u4E0E\u843D\u5730\u3002</li></ul><p><strong>\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\u7684\u6D4B\u8BD5\u6311\u6218</strong></p><p>\u7531\u4E8E\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u4E00\u4E2A\u5E94\u7528\u662F\u7531\u5F88\u591A\u76F8\u4E92\u72EC\u7ACB\u7684\u5FAE\u670D\u52A1\u7EC4\u6210\uFF0C\u6BCF\u4E2A\u5FAE\u670D\u52A1\u90FD\u4F1A\u5BF9\u5916\u66B4\u9732\u63A5\u53E3\uFF0C\u540C\u65F6\u8FD9\u4E9B\u5FAE\u670D\u52A1\u4E4B\u95F4\u5B58\u5728\u7EA7\u8054\u8C03\u7528\u5173\u7CFB\uFF0C\u4E5F\u5C31\u662F\u8BF4\u4E00\u4E2A\u5FAE\u670D\u52A1\u901A\u5E38\u8FD8\u4F1A\u53BB\u8C03\u7528\u5176\u4ED6\u5FAE\u670D\u52A1\uFF0C\u9274\u4E8E\u4EE5\u4E0A\u7279\u70B9\uFF0C\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\u7684\u6D4B\u8BD5\u6311\u6218\u4E3B\u8981\u6765\u81EA\u4E8E\u4EE5\u4E0B\u4E24\u4E2A\u65B9\u9762\uFF1A</p><ol><li>\u8FC7\u4E8E\u5E9E\u5927\u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\uFF1B</li><li>\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u8026\u5408\u5173\u7CFB\u3002</li></ol><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4F1A\u9488\u5BF9\u8FD9\u4E24\u9879\u6311\u6218\u5206\u522B\u5C55\u5F00\uFF0C\u5305\u62EC\u5B83\u4EEC\u4ECE\u4F55\u800C\u6765\uFF0C\u4EE5\u53CA\u5982\u4F55\u5E94\u5BF9\u8FD9\u4E9B\u6311\u6218\uFF0C\u6700\u7EC8\u5B8C\u6210\u6D4B\u8BD5\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u8FC7\u4E8E\u5E9E\u5927\u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF</strong></p><p>\u5728\u4F20\u7EDF\u7684 API \u6D4B\u8BD5\u4E2D\uFF0C\u6211\u4EEC\u7684\u6D4B\u8BD5\u7B56\u7565\u901A\u5E38\u662F\uFF1A</p><ul><li>\u6839\u636E\u88AB\u6D4B API \u8F93\u5165\u53C2\u6570\u7684\u5404\u79CD\u7EC4\u5408\u8C03\u7528 API\uFF0C\u5E76\u9A8C\u8BC1\u76F8\u5173\u7ED3\u679C\u7684\u6B63\u786E\u6027\uFF1B</li><li>\u8861\u91CF\u4E0A\u8FF0\u6D4B\u8BD5\u8FC7\u7A0B\u7684\u4EE3\u7801\u8986\u76D6\u7387\uFF1B</li><li>\u6839\u636E\u4EE3\u7801\u8986\u76D6\u7387\u8FDB\u4E00\u6B65\u627E\u51FA\u9057\u6F0F\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF1B</li><li>\u4EE5\u4EE3\u7801\u8986\u76D6\u7387\u8FBE\u6807\u4F5C\u4E3A API \u6D4B\u8BD5\u6210\u529F\u5B8C\u6210\u7684\u6807\u5FD7\u3002</li></ul><p>\u8FD9\u4E5F\u662F\u5355\u4F53\u67B6\u6784\u65F6\u4EE3\u4E3B\u6D41\u7684 API \u6D4B\u8BD5\u7B56\u7565\u3002\u4E3A\u4E86\u8BA9\u4F60\u66F4\u597D\u5730\u7406\u89E3\u8FD9\u79CD\u6D4B\u8BD5\u7B56\u7565\uFF0C\u6211\u6765\u4E3E\u4E00\u4E2A\u5B9E\u9645\u7684\u4F8B\u5B50\u3002</p><p>\u5047\u8BBE\u6211\u4EEC\u91C7\u7528\u5355\u4F53\u67B6\u6784\u5F00\u53D1\u4E86\u4E00\u4E2A\u7CFB\u7EDF\uFF0C\u8FD9\u4E2A\u7CFB\u7EDF\u5BF9\u5916\u63D0\u4F9B\u4E86 3 \u4E2A Restful API \u63A5\u53E3\uFF0C\u90A3\u4E48\u6211\u4EEC\u7684\u6D4B\u8BD5\u7B56\u7565\u5E94\u8BE5\u662F\uFF1A</p><ul><li>\u9488\u5BF9\u8FD9 3 \u4E2A API \u63A5\u53E3\uFF0C\u5206\u522B\u57FA\u4E8E\u8FB9\u754C\u503C\u548C\u7B49\u4EF7\u7C7B\u65B9\u6CD5\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u5E76\u6267\u884C\uFF1B</li><li>\u5728\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u542F\u7528\u4EE3\u7801\u8986\u76D6\u7387\u7EDF\u8BA1\uFF1B</li><li>\u5047\u8BBE\u6D4B\u8BD5\u5B8C\u6210\u540E\u4EE3\u7801\u884C\u8986\u76D6\u7387\u662F 80%\uFF0C\u90A3\u4E48\u6211\u4EEC\u5C31\u9700\u8981\u627E\u5230\u90A3\u4E9B\u8FD8\u6CA1\u6709\u88AB\u6267\u884C\u5230\u7684 20%\u7684\u4EE3\u7801\u884C\u3002\u6BD4\u5982\u56FE 2 \u4E2D\u4EE3\u7801\u7684\u7B2C 242 \u884C\u5C31\u662F\u6CA1\u6709\u88AB\u6267\u884C\u5230\uFF0C\u5206\u6790\u4EE3\u7801\u903B\u8F91\u540E\u53D1\u73B0\uFF0C\u6211\u4EEC\u9700\u8981\u6784\u9020\u201Cexpected!=actual\u201D\u624D\u80FD\u8986\u76D6\u8FD9\u4E2A\u672A\u80FD\u6267\u884C\u7684\u4EE3\u7801\u884C\uFF1B</li><li>\u6700\u7EC8\u6211\u4EEC\u8981\u4FDD\u8BC1\u4EE3\u7801\u8986\u76D6\u7387\u8FBE\u5230\u65E2\u5B9A\u7684\u8981\u6C42\uFF0C\u6BD4\u5982\u884C\u8986\u76D6\u7387\u8FBE\u5230 100%\uFF0C\u5B8C\u6210 API \u6D4B\u8BD5\u3002</li></ul><p><img src="https://static001.geekbang.org/resource/image/ab/e2/ab5e06ccd5d4e3925fe86024b54162e2.png" alt="\u57FA\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u6307\u5BFC\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u7684\u793A\u4F8B"></p><p><strong>\u800C\u5F53\u6211\u4EEC\u91C7\u7528\u5FAE\u670D\u52A1\u67B6\u6784\u65F6\uFF0C\u539F\u672C\u7684\u5355\u4F53\u5E94\u7528\u4F1A\u88AB\u62C6\u5206\u6210\u591A\u4E2A\u72EC\u7ACB\u6A21\u5757\uFF0C\u4E5F\u5C31\u662F\u5F88\u591A\u4E2A\u72EC\u7ACB\u7684 service\uFF0C\u539F\u672C\u5355\u4F53\u5E94\u7528\u7684\u5168\u5C40\u529F\u80FD\u5C06\u4F1A\u7531\u8FD9\u4E9B\u62C6\u5206\u5F97\u5230\u7684 API \u5171\u540C\u534F\u4F5C\u5B8C\u6210</strong>\u3002</p><p>\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u4E0A\u9762\u8FD9\u4E2A\u4F8B\u5B50\uFF0C\u6CA1\u6709\u5FAE\u670D\u52A1\u5316\u4E4B\u524D\uFF0C\u4E00\u5171\u6709 3 \u4E2A API \u63A5\u53E3\uFF0C\u5047\u5B9A\u73B0\u5728\u91C7\u7528\u5FAE\u670D\u52A1\u67B6\u6784\uFF0C\u8BE5\u7CFB\u7EDF\u88AB\u62C6\u5206\u6210\u4E86 10 \u4E2A\u72EC\u7ACB\u7684 service\uFF0C\u5982\u679C\u6BCF\u4E2A service \u5E73\u5747\u5BF9\u5916\u66B4\u9732 3 \u4E2A API \u63A5\u53E3\uFF0C\u90A3\u4E48\u603B\u5171\u9700\u8981\u6D4B\u8BD5\u7684 API \u63A5\u53E3\u6570\u91CF\u5C31\u591A\u8FBE 30 \u4E2A\u3002</p><p>\u5982\u679C\u6211\u8FD8\u6309\u7167\u4F20\u7EDF\u7684 API \u6D4B\u8BD5\u7B56\u7565\u6765\u6D4B\u8BD5\u8FD9\u4E9B API\uFF0C\u90A3\u4E48\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u5C31\u4F1A\u975E\u5E38\u591A\uFF0C\u8FC7\u591A\u7684\u6D4B\u8BD5\u7528\u4F8B\u5F80\u5F80\u5C31\u9700\u8981\u8017\u8D39\u5927\u91CF\u7684\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\u548C\u8D44\u6E90\u3002</p><p>\u4F46\u662F\uFF0C\u5728\u4E92\u8054\u7F51\u6A21\u5F0F\u4E0B\uFF0C\u4EA7\u54C1\u53D1\u5E03\u7684\u5468\u671F\u5F80\u5F80\u662F\u4EE5\u201C\u5929\u201D\u751A\u81F3\u662F\u4EE5\u201C\u5C0F\u65F6\u201D\u4E3A\u5355\u4F4D\u7684\uFF0C\u7559\u7ED9\u6D4B\u8BD5\u7684\u6267\u884C\u65F6\u95F4\u975E\u5E38\u6709\u9650\uFF0C\u6240\u4EE5\u5FAE\u670D\u52A1\u5316\u540E API \u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u7684\u663E\u8457\u589E\u957F\u5C31\u5BF9\u6D4B\u8BD5\u53D1\u8D77\u4E86\u5DE8\u5927\u7684\u6311\u6218\u3002</p><p>\u8FD9\u65F6\uFF0C\u6211\u4EEC\u8FEB\u5207\u9700\u8981\u627E\u5230\u4E00\u79CD\u65E2\u80FD\u4FDD\u8BC1 API \u8D28\u91CF\uFF0C\u53C8\u80FD\u51CF\u5C11\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u8FD9\u4E5F\u5C31\u662F\u6211\u63A5\u4E0B\u6765\u8981\u5206\u4EAB\u7684<strong>\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5</strong>\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u8026\u5408\u5173\u7CFB</strong></p><p>\u5FAE\u670D\u52A1\u5316\u540E\uFF0C\u670D\u52A1\u4E0E\u670D\u52A1\u95F4\u7684\u4F9D\u8D56\u4E5F\u53EF\u80FD\u4F1A\u7ED9\u6D4B\u8BD5\u5E26\u6765\u4E0D\u5C0F\u7684\u6311\u6218\u3002</p><p>\u5982\u56FE 3 \u6240\u793A\uFF0C\u5047\u5B9A\u6211\u4EEC\u7684\u88AB\u6D4B\u5BF9\u8C61\u662F Service T\uFF0C\u4F46\u662F Service T \u7684\u5185\u90E8\u53C8\u8C03\u7528\u4E86 Service X \u548C Service Y\u3002\u6B64\u65F6\uFF0C\u5982\u679C Service X \u548C Service Y \u7531\u4E8E\u5404\u79CD\u539F\u56E0\u5904\u4E8E\u4E0D\u53EF\u7528\u7684\u72B6\u6001\uFF0C\u90A3\u4E48\u6B64\u65F6\u5C31\u65E0\u6CD5\u5BF9 Service T \u8FDB\u884C\u5B8C\u6574\u7684\u6D4B\u8BD5\u3002</p><p><img src="https://static001.geekbang.org/resource/image/79/9b/79f5990fd864012cb1c7cd87c8e5079b.png" alt="API\u4E4B\u95F4\u7684\u8026\u5408\u793A\u4F8B"></p><p>\u6211\u4EEC\u8FEB\u5207\u9700\u8981\u4E00\u79CD\u65B9\u6CD5\u53EF\u4EE5\u5C06 Service T \u7684\u6D4B\u8BD5\u4E0E Service X \u548C Service Y \u89E3\u8026\u3002</p><p>\u89E3\u8026\u7684\u65B9\u5F0F\u901A\u5E38\u5C31\u662F\u5B9E\u73B0 Mock Service \u6765\u4EE3\u66FF\u88AB\u4F9D\u8D56\u7684\u771F\u5B9E Service\u3002\u5B9E\u73B0\u8FD9\u4E2A Mock Service \u7684\u5173\u952E\u70B9\u5C31\u662F\u8981\u80FD\u591F\u6A21\u62DF\u771F\u5B9E Service \u7684 Request \u548C Response\u3002\u5F53\u6211\u4ECB\u7ECD\u5B8C\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u540E\uFF0C\u4F60\u4F1A\u53D1\u73B0\u8FD9\u4E2A\u95EE\u9898\u4E5F\u5C31\u8FCE\u5203\u800C\u89E3\u4E86\u3002</p><p><strong>\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5</strong></p><p>\u90A3\u5230\u5E95\u4EC0\u4E48\u662F\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u5462\uFF1F\u76F4\u63A5\u4ECE\u6982\u5FF5\u7684\u89D2\u5EA6\u89E3\u91CA\uFF0C\u4F1A\u6709\u4E9B\u96BE\u4EE5\u7406\u89E3\u3002\u6240\u4EE5\u6211\u6253\u7B97\u6362\u4E2A\u65B9\u6CD5\u6765\u5E2E\u52A9\u4F60\u4ECE\u672C\u8D28\u4E0A\u771F\u6B63\u7406\u89E3\u4EC0\u4E48\u662F\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u3002\u63A5\u4E0B\u6765\uFF0C\u5C31\u8DDF\u7740\u6211\u7684\u601D\u8DEF\u8D70\u5427\u3002</p><p>\u9996\u5148\uFF0C\u6211\u4EEC\u6765\u770B\u56FE 4\uFF0C\u5047\u8BBE\u56FE 4 \u4E2D\u7684 Service A\u3001Service B \u548C Service T \u662F\u5FAE\u670D\u52A1\u62C6\u5206\u540E\u7684\u4E09\u4E2A Service\uFF0C\u5176\u4E2D Service T \u662F\u88AB\u6D4B\u8BD5\u5BF9\u8C61\uFF0C\u8FDB\u4E00\u6B65\u5047\u5B9A Service T \u7684\u6D88\u8D39\u8005\uFF08\u4E5F\u5C31\u662F\u4F7F\u7528\u8005\uFF09\u4E00\u5171\u6709\u4E24\u4E2A\uFF0C\u5206\u522B\u662F Service A \u548C Service B\u3002</p><p><img src="https://static001.geekbang.org/resource/image/4b/6f/4b60dcc958636c29ae8edd5e52db216f.png" alt="Service A\u3001Service B\u548CService T\u7684\u5173\u7CFB"></p><p>\u6309\u7167\u4F20\u7EDF\u7684 API \u6D4B\u8BD5\u7B56\u7565\uFF0C\u5F53\u6211\u4EEC\u9700\u8981\u6D4B\u8BD5 Service T \u65F6\uFF0C\u9700\u8981\u627E\u5230\u6240\u6709\u53EF\u80FD\u7684\u53C2\u6570\u7EC4\u5408\u4F9D\u6B21\u5BF9 Service T \u8FDB\u884C\u8C03\u7528\uFF0C\u540C\u65F6\u7ED3\u5408 Service T \u7684\u4EE3\u7801\u8986\u76D6\u7387\u8FDB\u4E00\u6B65\u8865\u5145\u9057\u6F0F\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u8FD9\u79CD\u601D\u8DEF\u672C\u8EAB\u6CA1\u6709\u4EFB\u4F55\u95EE\u9898\uFF0C\u4F46\u662F\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u4F1A\u975E\u5E38\u591A\u3002\u90A3\u6211\u4EEC\u5C31\u9700\u8981\u601D\u8003\uFF0C\u5982\u4F55\u65E2\u80FD\u4FDD\u8BC1 Service T \u7684\u8D28\u91CF\uFF0C\u53C8\u4E0D\u9700\u8981\u8986\u76D6\u5168\u90E8\u53EF\u80FD\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u9759\u4E0B\u5FC3\u6765\u60F3\u4E00\u4E0B\uFF0C\u4F60\u4F1A\u53D1\u73B0 Service T \u7684\u4F7F\u7528\u8005\u662F\u786E\u5B9A\u7684\uFF0C\u53EA\u6709 Service A \u548C Service B\uFF0C\u5982\u679C\u53EF\u4EE5\u628A Service A \u548C Service B \u5BF9 Service T \u6240\u6709\u53EF\u80FD\u7684\u8C03\u7528\u65B9\u5F0F\u90FD\u6D4B\u8BD5\u5230\uFF0C\u90A3\u4E48\u5C31\u4E00\u5B9A\u53EF\u4EE5\u4FDD\u8BC1 Service T \u7684\u8D28\u91CF\u3002\u5373\u4F7F\u5B58\u5728\u67D0\u4E9B Service T \u7684\u5176\u4ED6\u8C03\u7528\u65B9\u5F0F\u6709\u51FA\u9519\u7684\u53EF\u80FD\u6027\uFF0C\u90A3\u4E5F\u4E0D\u4F1A\u5F71\u54CD\u6574\u4E2A\u7CFB\u7EDF\u7684\u529F\u80FD\uFF0C\u56E0\u4E3A\u8FD9\u4E2A\u7CFB\u7EDF\u4E2D\u5E76\u6CA1\u6709\u5176\u4ED6 Service \u4F1A\u4EE5\u8FD9\u79CD\u53EF\u80FD\u51FA\u9519\u7684\u65B9\u5F0F\u6765\u8C03\u7528 Service T\u3002</p><p>\u73B0\u5728\uFF0C\u95EE\u9898\u5C31\u8F6C\u5316\u6210\u4E86\u5982\u4F55\u627E\u5230 Service A \u548C Service B \u5BF9 Service T \u6240\u6709\u53EF\u80FD\u7684\u8C03\u7528\u65B9\u5F0F\u3002\u5982\u679C\u80FD\u591F\u627E\u51FA\u8FD9\u6837\u7684\u8C03\u7528\u96C6\u5408\uFF0C\u5E76\u4EE5\u6B64\u4F5C\u4E3A Service T \u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u90A3\u4E48\u53EA\u8981\u8FD9\u4E9B\u6D4B\u8BD5\u7528\u4F8B 100%\u901A\u8FC7\uFF0CService T \u7684\u8D28\u91CF\u4E5F\u5C31\u4E0D\u5728\u8BDD\u4E0B\u4E86\u3002</p><p>\u4ECE\u672C\u8D28\u4E0A\u6765\u8BB2\uFF0C\u8FD9\u6837\u7684\u6D4B\u8BD5\u7528\u4F8B\u96C6\u5408\u5176\u5B9E\u5C31\u662F\uFF0CService T \u53EF\u4EE5\u5BF9\u5916\u63D0\u4F9B\u7684\u670D\u52A1\u7684\u5951\u7EA6\uFF0C\u6240\u4EE5\u6211\u4EEC\u628A\u8FD9\u4E2A\u6D4B\u8BD5\u7528\u4F8B\u7684\u96C6\u5408\u79F0\u4E3A\u201C\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u201D\u3002</p><p>\u90A3\u4E48\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u8981\u89E3\u51B3\u7684\u95EE\u9898\u5C31\u662F\uFF1A\u5982\u4F55\u624D\u80FD\u627E\u5230 Service A \u548C Service B \u5BF9 Service T \u7684\u6240\u6709\u53EF\u80FD\u8C03\u7528\u4E86\u3002\u5176\u5B9E\u8FD9\u4E5F\u5F88\u7B80\u5355\uFF0C\u5728\u903B\u8F91\u7ED3\u6784\u4E0A\uFF0C\u6211\u4EEC\u53EA\u8981\u5728 Service T \u524D\u653E\u7F6E\u4E00\u4E2A\u4EE3\u7406\uFF0C\u6240\u6709\u8FDB\u51FA Service T \u7684 Request \u548C Response \u90FD\u4F1A\u7ECF\u8FC7\u8FD9\u4E2A\u4EE3\u7406\uFF0C\u5E76\u88AB\u8BB0\u5F55\u6210 JSON \u6587\u4EF6\uFF0C\u4E5F\u5C31\u6784\u6210\u4E86 Service T \u7684\u5951\u7EA6\u3002</p><p>\u5982\u56FE 5 \u6240\u793A\uFF0C\u5C31\u662F\u8FD9\u4E2A\u8FC7\u7A0B\u7684\u539F\u7406\u4E86\u3002</p><p><img src="https://static001.geekbang.org/resource/image/1e/86/1e9c9cb78a02e3675e612da46e2c1b86.png" alt="\u6536\u96C6\u6D88\u8D39\u8005\u5951\u7EA6\u7684\u903B\u8F91\u539F\u7406"></p><p>\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u6211\u4EEC\u4E0D\u53EF\u80FD\u5728\u6BCF\u4E2A Service \u524D\u53BB\u653E\u7F6E\u8FD9\u6837\u4E00\u4E2A\u4EE3\u7406\u3002\u4F46\u662F\uFF0C\u5FAE\u670D\u52A1\u67B6\u6784\u4E2D\u5F80\u5F80\u4F1A\u5B58\u5728\u4E00\u4E2A\u53EB\u4F5C API Gateway \u7684\u7EC4\u4EF6\uFF0C\u7528\u4E8E\u8BB0\u5F55\u6240\u6709 API \u4E4B\u95F4\u76F8\u4E92\u8C03\u7528\u5173\u7CFB\u7684\u65E5\u5FD7\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u89E3\u6790 API Gateway \u7684\u65E5\u5FD7\u5206\u6790\u5F97\u5230\u6BCF\u4E2A Service \u7684\u5951\u7EA6\u3002</p><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u6E05\u695A\u5730\u77E5\u9053\u4E86\u5982\u4F55\u83B7\u53D6 Service \u7684\u5951\u7EA6\uFF0C\u5E76\u7531\u6B64\u6765\u6784\u6210 Service \u7684\u5951\u7EA6\u6D4B\u8BD5\u7528\u4F8B\u3002\u63A5\u4E0B\u6765\uFF0C\u5C31\u662F\u5982\u4F55\u89E3\u51B3\u5FAE\u670D\u52A1\u4E4B\u95F4\u8026\u5408\u5173\u7CFB\u5E26\u6765\u7684\u95EE\u9898\u4E86\u3002</p><p><strong>\u5FAE\u670D\u52A1\u6D4B\u8BD5\u7684\u4F9D\u8D56\u89E3\u8026\u548C Mock Service</strong></p><p>\u5728\u524D\u9762\u7684\u5185\u5BB9\u4E2D\uFF0C\u6211\u8BF4\u8FC7\u4E00\u53E5\u8BDD\uFF1A\u5B9E\u73B0 Mock Service \u7684\u5173\u952E\uFF0C\u5C31\u662F\u8981\u80FD\u591F\u6A21\u62DF\u88AB\u66FF\u4EE3 Service \u7684 Request \u548C Response\u3002</p><p>\u6B64\u65F6\u6211\u4EEC\u5DF2\u7ECF\u62FF\u5230\u4E86\u5951\u7EA6\uFF0C\u5951\u7EA6\u7684\u672C\u8D28\u5C31\u662F Request \u548C Response \u7684\u7EC4\u5408\uFF0C\u5177\u4F53\u7684\u8868\u73B0\u5F62\u5F0F\u5F80\u5F80\u662F JSON \u6587\u4EF6\uFF0C\u6B64\u65F6\u6211\u4EEC\u5C31\u53EF\u4EE5\u7528\u8BE5\u5951\u7EA6\u7684 JSON \u6587\u4EF6\u4F5C\u4E3A Mock Service \u7684\u4F9D\u636E\uFF0C\u4E5F\u5C31\u662F\u5728\u6536\u5230\u4EC0\u4E48 Request \u7684\u65F6\u5019\u5E94\u8BE5\u56DE\u590D\u4EC0\u4E48 Response\u3002</p><p>\u4E0B\u9762\u7684\u56FE 6 \u5C31\u89E3\u91CA\u4E86\u8FD9\u4E00\u5173\u7CFB\uFF0C\u5F53\u7528 Service X \u7684\u5951\u7EA6\u542F\u52A8 Mock Service X \u540E\uFF0C\u539F\u672C\u771F\u5B9E\u7684 Service X \u5C06\u88AB Mock Service X \u66FF\u4EE3\uFF0C\u4E5F\u5C31\u89E3\u8026\u4E86\u670D\u52A1\u4E4B\u95F4\u7684\u4F9D\u8D56\uFF0C\u56FE 6 \u4E2D\u7684 Service Y \u4E5F\u662F\u4E00\u6837\u7684\u9053\u7406\u3002</p><p><img src="https://static001.geekbang.org/resource/image/e1/01/e18bf590c818e5dc26e85a5e07eb1401.png" alt="\u57FA\u4E8EMock Service\u89E3\u51B3API\u4E4B\u95F4\u7684\u8C03\u7528\u4F9D\u8D56"></p><p><strong>\u4EE3\u7801\u5B9E\u4F8B</strong></p><p>\u81EA\u6B64\uFF0C\u6211\u5DF2\u7ECF\u8BB2\u5B8C\u4E86\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u7684\u539F\u7406\uFF0C\u4F60\u662F\u5426\u5DF2\u7ECF\u90FD\u771F\u6B63\u7406\u89E3\u5E76\u638C\u63E1\u4E86\u5462\uFF1F</p><p>\u7531\u4E8E\u8FD9\u90E8\u5206\u5185\u5BB9\u7684\u7406\u8BBA\u77E5\u8BC6\u6BD4\u8F83\u591A\uFF0C\u4E3A\u4E86\u5E2E\u4F60\u66F4\u597D\u5730\u7406\u89E3\u8FD9\u4E9B\u6982\u5FF5\uFF0C\u6211\u627E\u4E86\u4E00\u4E2A\u57FA\u4E8E Spring Cloud Contract \u7684\u5B9E\u9645\u4EE3\u7801\u7684\u793A\u4F8B\u6F14\u793A\u5951\u7EA6\u6587\u4EF6\u683C\u5F0F\u3001\u6D88\u8D39\u8005\u5951\u7EA6\u6D4B\u8BD5\u4EE5\u53CA\u5FAE\u670D\u52A1\u4E4B\u95F4\u89E3\u8026\uFF0C\u5E0C\u671B\u53EF\u4EE5\u5E2E\u5230\u4F60\u3002</p><p>\u5177\u4F53\u7684\u5B9E\u4F8B\u4EE3\u7801\uFF0C\u4F60\u53EF\u4EE5\u4ECEhttps://github.com/SpectoLabs/spring-cloud-contract-blog\u4E0B\u8F7D\uFF0C\u8BE6\u7EC6\u7684\u4EE3\u7801\u89E3\u8BFB\u53EF\u4EE5\u53C2\u8003https://specto.io/blog/2016/11/16/spring-cloud-contract/\u3002</p><p>\u8FD9\u4E2A\u5B9E\u4F8B\u4EE3\u7801\uFF0C\u57FA\u4E8E Spring Boot \u5B9E\u73B0\u4E86\u4E24\u4E2A\u5FAE\u670D\u52A1\uFF1A\u8BA2\u9605\u670D\u52A1\uFF08subscription-service\uFF09\u548C\u8D26\u6237\u670D\u52A1\uFF08account-service\uFF09\uFF0C\u5176\u4E2D\u8BA2\u9605\u670D\u52A1\u4F1A\u8C03\u7528\u8D26\u6237\u670D\u52A1\u3002\u8FD9\u4E2A\u5B9E\u4F8B\u57FA\u4E8E Spring Cloud Contract\uFF0C\u6240\u4EE5\u5951\u7EA6\u662F\u901A\u8FC7 Groovy \u8BED\u8A00\u63CF\u8FF0\u7684\uFF0C\u4E5F\u5C31\u662F\u8BF4\u5B9E\u4F8B\u4E2D\u4F1A\u901A\u8FC7 Groovy \u8BED\u8A00\u63CF\u8FF0\u7684\u8D26\u6237\u670D\u52A1\u5951\u7EA6\u6765\u6A21\u62DF\u771F\u5B9E\u7684\u8D26\u6237\u670D\u52A1\u3002</p><p>\u8FD9\u4E2A\u5B9E\u4F8B\u7684\u903B\u8F91\u5173\u7CFB\u5982\u56FE 7 \u6240\u793A\u3002</p><p><img src="https://static001.geekbang.org/resource/image/db/fa/db1b2b058505fef62805f9077e1982fa.png" alt="\u57FA\u4E8ESpring Cloud Contract\u7684\u5951\u7EA6\u6D4B\u8BD5\u5B9E\u4F8B"></p><p><strong>\u603B\u7ED3</strong></p><p>\u5355\u4F53\u67B6\u6784\uFF0C\u5177\u6709\u7075\u6D3B\u6027\u5DEE\u3001\u53EF\u6269\u5C55\u6027\u5DEE\u3001\u53EF\u7EF4\u62A4\u6027\u5DEE\u7B49\u5C40\u9650\u6027\uFF0C\u6240\u4EE5\u6709\u4E86\u5FAE\u670D\u52A1\u67B6\u6784\u3002</p><p>\u5FAE\u670D\u52A1\u67B6\u6784\u7684\u672C\u8EAB\u7684\u7279\u70B9\uFF0C\u6BD4\u5982\u5FAE\u670D\u52A1\u6570\u91CF\u591A\uFF0C\u5404\u4E2A\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u76F8\u4E92\u8C03\u7528\uFF0C\u51B3\u5B9A\u4E86\u4E0D\u80FD\u7EE7\u7EED\u91C7\u7528\u4F20\u7EDF API \u6D4B\u8BD5\u7684\u7B56\u7565\u3002</p><p>\u4E3A\u4E86\u65E2\u80FD\u4FDD\u8BC1 API \u8D28\u91CF\uFF0C\u53C8\u80FD\u51CF\u5C11\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\uFF0C\u4E8E\u662F\u6709\u4E86\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u3002\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u7684\u6838\u5FC3\u601D\u60F3\u662F\uFF1A\u53EA\u6D4B\u8BD5\u90A3\u4E9B\u771F\u6B63\u88AB\u5B9E\u9645\u4F7F\u7528\u5230\u7684 API \u8C03\u7528\uFF0C\u5982\u679C\u6CA1\u6709\u88AB\u4F7F\u7528\u5230\u7684\uFF0C\u5C31\u4E0D\u53BB\u6D4B\u8BD5\u3002</p><p>\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u7531\u4E8E\u6536\u96C6\u5230\u4E86\u5B8C\u6574\u7684\u5951\u7EA6\uFF0C\u6240\u4EE5\u57FA\u4E8E\u5951\u7EA6\u7684 Mock Service \u5B8C\u7F8E\u5730\u89E3\u51B3\u4E86 API \u4E4B\u95F4\u76F8\u4E92\u4F9D\u8D56\u8026\u5408\u7684\u95EE\u9898\u3002</p><p>\u8FD9\u5DF2\u7ECF\u662F API \u81EA\u52A8\u5316\u6D4B\u8BD5\u7CFB\u5217\u7684\u6700\u540E\u4E00\u7BC7\u6587\u7AE0\u4E86\uFF0C\u77ED\u77ED\u7684\u4E09\u7BC7\u6587\u7AE0\u53EF\u80FD\u8BA9\u4F60\u611F\u89C9\u610F\u72B9\u672A\u5C3D\uFF0C\u4E5F\u53EF\u80FD\u611F\u89C9\u5E76\u6CA1\u6709\u6DB5\u76D6\u5230\u4F60\u5728\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\u9047\u5230\u7684 API \u6D4B\u8BD5\u7684\u6240\u6709\u95EE\u9898\uFF0C\u4F46\u662F\u4E00\u4E2A\u4E13\u680F\u533A\u533A\u51E0\u5341\u7BC7\u6587\u7AE0\u7684\u786E\u65E0\u6CD5\u9762\u9762\u4FF1\u5230\u3002</p><p>\u6211\u901A\u8FC7\u8FD9\u4E2A\u4E13\u680F\u66F4\u60F3\u8FBE\u5230\u7684\u76EE\u7684\u662F\uFF1A\u8BB2\u6E05\u695A\u67D0\u4E00\u6280\u672F\u7684\u6765\u9F99\u53BB\u8109\u53CA\u5176\u5E94\u7528\u573A\u666F\uFF0C\u4F46\u662F\u5F88\u591A\u5177\u4F53\u64CD\u4F5C\u7EA7\u522B\u3001\u4EE3\u7801\u5B9E\u73B0\u7EA7\u522B\u7684\u5185\u5BB9\uFF0C\u8FD8\u662F\u9700\u8981\u4F60\u5728\u5B9E\u8DF5\u4E2D\u4E0D\u65AD\u79EF\u7D2F\u3002</p><p>\u6240\u4EE5\uFF0C\u5982\u679C\u4F60\u8FD8\u6709\u5173\u4E8E API \u6D4B\u8BD5\u7684\u5176\u4ED6\u95EE\u9898\uFF0C\u975E\u5E38\u6B22\u8FCE\u4F60\u7ED9\u6211\u7559\u8A00\u8BA8\u8BBA\uFF0C\u8BA9\u6211\u4EEC\u4E00\u8D77\u6765\u78B0\u649E\u51FA\u601D\u60F3\u706B\u82B1\u5427\uFF01</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u4E2D\uFF0C\u5BF9\u4E8E\u90A3\u4E9B\u65B0\u5F00\u53D1\u7684 API\uFF0C\u6216\u8005\u52A0\u4E86\u65B0\u529F\u80FD\u7684 API\uFF0C\u7531\u4E8E\u4E4B\u524D\u90FD\u6CA1\u6709\u5B9E\u9645\u7684\u6D88\u8D39\u8005\uFF0C\u6240\u4EE5\u4F60\u65E0\u6CD5\u901A\u8FC7 API Gateway \u65B9\u6CD5\u5F97\u5230\u5951\u7EA6\u3002\u5BF9\u4E8E\u8FD9\u79CD\u60C5\u51B5\uFF0C\u4F60\u4F1A\u91C7\u7528\u4EC0\u4E48\u65B9\u6CD5\u6765\u89E3\u51B3\u5462\uFF1F</p>',78);function i(t,s){return c}var g=e(r,[["render",i],["__file","24.html.vue"]]);export{g as default};
